class Solution:
    def minMaxGame(self, nums):
        cur = list(nums)
        while len(cur) > 1:
            half = len(cur) // 2
            nxt = [0] * half
            for i in range(half):
                a, b = cur[2 * i], cur[2 * i + 1]
                nxt[i] = min(a, b) if i % 2 == 0 else max(a, b)
            cur = nxt
        return cur[0]

