var minMaxGame = function(nums) {
    let cur = nums.slice();
    while (cur.length > 1) {
        const half = cur.length / 2;
        const nxt = new Array(half);
        for (let i = 0; i < half; i++) {
            const a = cur[2 * i], b = cur[2 * i + 1];
            nxt[i] = (i % 2 === 0) ? Math.min(a, b) : Math.max(a, b);
        }
        cur = nxt;
    }
    return cur[0];
};
